import {
  usePersistedFilter,
  usePersistedFilterMutation,
} from './usePersistedFilter.js';
import { useRecentAndPinnedFiltersStore } from './useRecentFiltersStore.js';
import type { StoredFilter } from '../../state/recent-pinned-store.js';

/**
 * Allows access to the namespaced recent filters store.
 * @internal
 */
export function useRecentFilters(name: string | null = null): StoredFilter[] {
  const setFilters = useRecentAndPinnedFiltersStore(
    (state) => state.setRecentFilters,
    name,
  );
  const filters = useRecentAndPinnedFiltersStore(
    (state) => state.recentFilters,
    name,
  );

  usePersistedFilter(
    name,
    `strato-FilterField-recentFilters-${name}`,
    setFilters,
  );

  return filters;
}

/**
 * Allows access to the namespaced recent filters store setter.
 * @internal
 */
export function useRecentFilterMutation(
  name: string | null = null,
): (value: string) => Promise<void | StoredFilter[]> {
  const { mutateAsync } = usePersistedFilterMutation(
    `strato-FilterField-recentFilters-${name}`,
    name,
    'save',
  );

  return mutateAsync;
}
